#include <bits/stdc++.h>
using namespace std;

const int N=2e5+10;

int c,T,n,l[N][2],r[N][2],ls[N*2];
long long s[N*2],al[N*2],ar[N*2],cl[N*2],cr[N*2];
map<int,int> mp;

int main(){
    scanf("%d%d",&c,&T);
    while(T--){
        mp.clear();
        scanf("%d",&n);
        for(int i=1;i<=n;i++){
            scanf("%d%d%d%d",&l[i][0],&r[i][0],&l[i][1],&r[i][1]);
            r[i][1]++;
            ls[2*i-1]=l[i][1];
            ls[2*i]=r[i][1];
        }
        sort(ls+1,ls+2*n+1);
        int len=unique(ls+1,ls+2*n+1)-ls-1;
        for(int i=1;i<=len;i++){
            mp[ls[i]]=i;
            s[i]=al[i]=ar[i]=cl[i]=cr[i]=0;
        }
        for(int i=1;i<=n;i++){
            s[mp[l[i][1]]]+=r[i][0];
            s[mp[r[i][1]]]-=r[i][0];
            al[mp[r[i][1]]]+=l[i][0];
            ar[mp[r[i][1]]]+=r[i][0];
            cl[1]+=l[i][0];
            cl[mp[l[i][1]]]-=l[i][0];
            cr[1]+=r[i][0];
            cr[mp[l[i][1]]]-=r[i][0];
        }
        for(int i=1;i<=len;i++){
            s[i]+=s[i-1];
            al[i]+=al[i-1];
            ar[i]+=ar[i-1];
            cl[i]+=cl[i-1];
            cr[i]+=cr[i-1];
        }
        int ans=0;
        for(int i=1;i<len;i++){
            if(s[i] && ar[i]+s[i]>=cl[i] && al[i]-s[i]+1<=cr[i])
                ans+=ls[i+1]-ls[i];
            al[i]-s[i];
        }
        printf("%d\n",ans);
    }
    return 0;
}
